import React, { useEffect, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  RefreshControl,
  ActivityIndicator,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { useAppDispatch, useAppSelector } from "src/store/hooks";
import {
  fetchRecentReviews,
  fetchTrendingLocations,
  fetchSafetyInsights,
  loadCommunityFeedMode,
  saveCommunityFeedMode,
  setNavigationIntent,
} from "src/store/locationsSlice";
import { theme } from "src/styles/theme";
import { useRealtimeReviews } from "src/hooks/useRealtimeReviews";
import { APP_CONFIG } from "@/config/appConfig";
import { router } from "expo-router";
import type { SafetyInsight } from "@/types/supabase";
import ProfileBanner from "@/components/ProfileBanner";
import { checkProfileCompleteness } from "@/utils/profileValidation";
import { shouldShowBanner } from "@/store/profileBannerSlice";
import { notify } from "@/utils/notificationService";
import { logger } from "@/utils/logger";
import UserProfileModal from "@/components/UserProfileModal";
import {
  getSafetyColor as getRatingColor,
  getSeverityColor,
} from "@/utils/safetyHelpers";
import { formatTimeAgo } from "@/utils/timeHelpers";
import VoteButtons from "@/components/VoteButtons";
import { commonStyles } from "@/styles/common";
import MapFiltersModal, {
  MapFilters,
  DEFAULT_FILTERS,
} from "@/components/MapFiltersModal";
import { GlobalPremiumPromptModal } from "@/components/PremiumGate";
import { useAuth } from "@/providers/AuthProvider";
import { AdBanner } from "@/components/ads/AdBanner";
import { useTranslation } from "react-i18next";

export default function CommunityScreen() {
  const { t } = useTranslation();

  const dispatch = useAppDispatch();
  const {
    communityReviews,
    communityLoading,
    trendingLocations,
    trendingLoading,
    safetyInsights,
    safetyInsightsLoading,
    userLocation,
    mapCenter,
    communityFeedMode,
  } = useAppSelector((state) => state.locations);

  const { searchRadiusKm: userSearchRadiusKm } = useAppSelector(
    (state) => state.user,
  );

  const [refreshing, setRefreshing] = React.useState(false);

  const { profile } = useAppSelector((state) => state.user);
  const bannerState = useAppSelector((state) => state.profileBanner);
  const [profileModalVisible, setProfileModalVisible] = useState(false);
  const [selectedUserId, setSelectedUserId] = useState<string | null>(null);
  const [filtersModalVisible, setFiltersModalVisible] = useState(false);
  const [communityFilters, setCommunityFilters] =
    useState<MapFilters>(DEFAULT_FILTERS);
  const { user } = useAuth();

  // Check profile completeness for recommendations
  const profileCheck = React.useMemo(() => {
    if (!profile) return { canUse: true, missingFields: [] };

    const validation = checkProfileCompleteness(profile, "RECOMMENDATIONS");
    return {
      canUse: validation.canUseFeature,
      missingFields: validation.missingFieldsForFeature,
    };
  }, [profile]);

  const filteredReviews = React.useMemo(() => {
    if (!communityReviews) return [];

    return communityReviews.filter((review: any) => {
      // Get the safety rating
      const rating = parseFloat(review.safety_rating) || 0;
      if (communityFilters.showMyReviewsOnly) {
        if (review.user_id !== user?.id) return false;
      }
      // Filter by minimum safety rating
      if (communityFilters.minSafetyRating !== null) {
        if (rating < communityFilters.minSafetyRating) return false;
      }

      // Filter by place type (if location has place_type)
      if (communityFilters.placeTypes.length > 0) {
        if (!communityFilters.placeTypes.includes(review.place_type))
          return false;
      }

      return true;
    });
  }, [communityReviews, communityFilters]);

  // Determine if we should show the banner
  const showProfileBanner = React.useMemo(() => {
    if (profileCheck.canUse) return false;
    return shouldShowBanner(
      bannerState,
      APP_CONFIG.PROFILE_COMPLETION.BANNERS.BANNER_TYPES
        .RECOMMENDATIONS_INCOMPLETE,
    );
  }, [profileCheck.canUse, bannerState]);

  // Calculate fetch radius based on user preference
  const getFetchRadius = (): number => {
    if (userSearchRadiusKm >= 999999) {
      // Infinite search - use Earth's half-circumference
      return 20000000; // 20,000 km in meters
    }
    return userSearchRadiusKm * 1000; // Convert km to meters
  };

  useRealtimeReviews();

  useEffect(() => {
    dispatch(loadCommunityFeedMode());
  }, []);

  // Load data on mount AND reload when location or mode changes
  useEffect(() => {
    const coords = communityFeedMode === "near_me" ? userLocation : mapCenter;

    if (!coords) return;

    const fetchData = async () => {
      const fetchRadius = getFetchRadius();

      try {
        await Promise.all([
          dispatch(
            fetchRecentReviews({
              limit: APP_CONFIG.COMMUNITY.REVIEWS_PER_PAGE,
              latitude: coords.latitude,
              longitude: coords.longitude,
              radius: fetchRadius, // ✅ Use user's radius
            }),
          ).unwrap(),
          dispatch(
            fetchTrendingLocations({
              daysWindow: APP_CONFIG.COMMUNITY.TRENDING_TIMEFRAME_DAYS,
              maxResults: APP_CONFIG.COMMUNITY.REVIEWS_PER_PAGE,
            }),
          ).unwrap(),
          dispatch(
            fetchSafetyInsights({
              latitude: coords.latitude,
              longitude: coords.longitude,
              radius: fetchRadius, // ✅ Use user's radius
              maxResults: 5,
            }),
          ).unwrap(),
        ]);
      } catch (error) {
        logger.error("Error loading community data:", error);
      }
    };

    fetchData();
  }, [
    userLocation?.latitude,
    userLocation?.longitude,
    mapCenter?.latitude,
    mapCenter?.longitude,
    communityFeedMode,
    userSearchRadiusKm,
    dispatch,
  ]);

  const handleUserProfilePress = (userId: string) => {
    setSelectedUserId(userId);
    setProfileModalVisible(true);
  };

  const loadCommunityData = async () => {
    const coords = communityFeedMode === "near_me" ? userLocation : mapCenter;
    if (!coords) return;

    const fetchRadius = getFetchRadius();

    try {
      await Promise.all([
        dispatch(
          fetchRecentReviews({
            limit: 10,
            latitude: coords.latitude,
            longitude: coords.longitude,
            radius: fetchRadius, // ✅ Use user's radius
          }),
        ).unwrap(),
        dispatch(
          fetchTrendingLocations({
            daysWindow: APP_CONFIG.COMMUNITY.TRENDING_TIMEFRAME_DAYS,
            maxResults: APP_CONFIG.COMMUNITY.REVIEWS_PER_PAGE,
          }),
        ).unwrap(),
        dispatch(
          fetchSafetyInsights({
            latitude: coords.latitude,
            longitude: coords.longitude,
            radius: fetchRadius, // ✅ Use user's radius
            maxResults: APP_CONFIG.COMMUNITY.REVIEWS_PER_PAGE,
          }),
        ).unwrap(),
      ]);
    } catch (error) {
      logger.error("Error loading community data:", error);
    }
  };

  const onRefresh = async () => {
    setRefreshing(true);
    await loadCommunityData();
    setRefreshing(false);
  };

  const handleInsightPress = (insight: SafetyInsight) => {
    dispatch(
      setNavigationIntent({
        targetTab: "map",
        locationId: insight.location_id,
        action: "view_location",
      }),
    );
    router.push("/(tabs)");
  };

  const handleToggleMode = async () => {
    const newMode = communityFeedMode === "near_me" ? "map_area" : "near_me";
    await dispatch(saveCommunityFeedMode(newMode)).unwrap();
  };

  const renderSafetyInsight = (insight: SafetyInsight) => {
    const timeAgo = formatTimeAgo(insight.created_at);
    const getSeverityBg = () => {
      switch (insight.severity) {
        case "high":
          return theme.colors.backgroundSecondary;
        case "medium":
          return theme.colors.backgroundSecondary;
        case "low":
          return theme.colors.backgroundSecondary;
        default:
          return theme.colors.backgroundSecondary;
      }
    };

    return (
      <TouchableOpacity
        key={`${insight.insight_type}-${insight.location_id}`}
        style={[
          styles.insightCard,
          {
            backgroundColor: getSeverityBg(),
            borderColor: getSeverityColor(insight.severity),
          },
        ]}
        onPress={() => handleInsightPress(insight)}
      >
        <View style={styles.insightContent}>
          <Text
            style={[
              styles.insightMessage,
              { color: getSeverityColor(insight.severity) },
            ]}
          >
            {insight.message}
          </Text>
          <Text style={styles.insightAddress} numberOfLines={1}>
            {insight.location_address}
          </Text>
          <Text style={styles.insightTime}>{timeAgo}</Text>
        </View>
      </TouchableOpacity>
    );
  };

  const renderReviewItem = (review: any) => {
    const timeAgo = formatTimeAgo(review.created_at);

    // Parse the overall_rating string to float
    const rating = parseFloat(review.overall_rating) || 0;

    const handleReviewPress = () => {
      // Set navigation intent for map tab
      dispatch(
        setNavigationIntent({
          targetTab: "map",
          locationId: review.location_id,
          action: "view_location",
        }),
      );

      // Navigate to map tab
      router.push("/(tabs)");
    };

    return (
      <TouchableOpacity
        key={review.id}
        style={styles.reviewCard}
        onPress={handleReviewPress}
      >
        <View style={styles.reviewHeader}>
          <View style={styles.locationInfo}>
            <Text style={styles.locationName}>{review.location_name}</Text>
            <Text style={styles.locationAddress} numberOfLines={1}>
              {review.location_address}
            </Text>
          </View>
          <View
            style={[
              styles.ratingBadge,
              { backgroundColor: getRatingColor(rating) },
            ]}
          >
            <Text style={styles.ratingText}>{rating.toFixed(1)}</Text>
          </View>
        </View>

        <Text style={styles.reviewTitle}>{review.title}</Text>
        <Text style={styles.reviewBody} numberOfLines={2}>
          {review.content}
        </Text>

        <View style={styles.reviewFooter}>
          {review.user_demographics?.full_name?.length > 0 &&
            review.user_demographics.show_demographics && (
              <TouchableOpacity
                style={styles.userInfoName}
                onPress={() => handleUserProfilePress(review.user_id)}
              >
                <Text style={[styles.demographicsText, styles.clickableName]}>
                  Review by {review.user_demographics.full_name}
                </Text>
              </TouchableOpacity>
            )}
          <View style={styles.userInfo}>
            {review.user_demographics?.show_demographics ? (
              <Text style={styles.demographicsText}>
                {[
                  review.user_demographics.race_ethnicity?.length > 0 &&
                    review.user_demographics.race_ethnicity.join(", "),
                  review.user_demographics.gender,
                  review.user_demographics.lgbtq_status && "LGBTQ+",
                  review.user_demographics.disability_status?.length > 0 &&
                    review.user_demographics.disability_status.join(", "),
                ]
                  .filter(Boolean)
                  .join(" • ")}
              </Text>
            ) : (
              <Text style={styles.anonymousText}>
                {t("community.anonymous_reviewer")}
              </Text>
            )}
          </View>
          <Text style={styles.timeText}>{timeAgo}</Text>
        </View>
        <VoteButtons
          reviewId={review.id}
          initialHelpfulCount={review.helpful_count || 0}
          initialUnhelpfulCount={review.unhelpful_count || 0}
          currentUserVote={null}
        />
      </TouchableOpacity>
    );
  };

  const renderTrendingLocation = (
    id: string,
    name: string,
    trend: string,
    reviews: number,
  ) => {
    const handleTrendingPress = () => {
      dispatch(
        setNavigationIntent({
          targetTab: "map",
          locationId: id,
          action: "view_location",
        }),
      );
      router.push("/(tabs)");
    };

    return (
      <TouchableOpacity
        key={id}
        style={styles.trendingCard}
        onPress={handleTrendingPress}
      >
        <View>
          <Text style={styles.trendingName}>{name}</Text>
          <Text style={styles.trendingStats}>{reviews} reviews this week</Text>
        </View>
        <View style={styles.trendBadge}>
          <Ionicons
            name={trend === "up" ? "trending-up" : "trending-down"}
            size={20}
            color={
              trend === "up" ? theme.colors.safeGreen : theme.colors.unsafeRed
            }
          />
        </View>
      </TouchableOpacity>
    );
  };

  if (communityLoading && communityReviews.length === 0) {
    return (
      <SafeAreaView style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
          <Text style={commonStyles.loadingText}>
            Loading community updates...
          </Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={commonStyles.container}>
      {/* Profile Completion Banner */}
      {showProfileBanner && (
        <ProfileBanner
          bannerType={
            APP_CONFIG.PROFILE_COMPLETION.BANNERS.BANNER_TYPES
              .RECOMMENDATIONS_INCOMPLETE
          }
          missingFields={profileCheck.missingFields}
          visible={showProfileBanner}
        />
      )}
      <ScrollView
        style={commonStyles.scrollView}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} />
        }
        showsVerticalScrollIndicator={false}
      >
        {/* Header */}
        <View style={commonStyles.subHeader}>
          <Text style={styles.screenTitle}>{t("community.community")}</Text>
          <Text style={styles.screenSubtitle}>
            Recent reviews and safety updates from travelers like you
          </Text>

          <View style={styles.modeToggleContainer}>
            <TouchableOpacity
              style={[
                styles.modeButton,
                communityFeedMode === "near_me" && styles.modeButtonActive,
              ]}
              onPress={handleToggleMode}
            >
              <Ionicons
                name="navigate"
                size={18}
                color={
                  communityFeedMode === "near_me"
                    ? theme.colors.card
                    : theme.colors.primary
                }
              />
              <Text
                style={[
                  styles.modeButtonText,
                  communityFeedMode === "near_me" &&
                    styles.modeButtonTextActive,
                ]}
              >
                Within my Search Radius
              </Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[
                styles.modeButton,
                communityFeedMode === "map_area" && styles.modeButtonActive,
              ]}
              onPress={handleToggleMode}
            >
              <Ionicons
                name="map"
                size={18}
                color={
                  communityFeedMode === "map_area"
                    ? theme.colors.card
                    : theme.colors.primary
                }
              />
              <Text
                style={[
                  styles.modeButtonText,
                  communityFeedMode === "map_area" &&
                    styles.modeButtonTextActive,
                ]}
              >
                Visible Map Area
              </Text>
            </TouchableOpacity>
          </View>
        </View>
        {/* No location available message */}
        {(!userLocation && communityFeedMode === "near_me") ||
        (!mapCenter && communityFeedMode === "map_area") ? (
          <View style={styles.noLocationContainer}>
            <Ionicons
              name="location-outline"
              size={48}
              color={theme.colors.textLight}
            />
            <Text style={styles.noLocationTitle}>
              {t("community.location_required")}
            </Text>
            <Text style={styles.noLocationText}>
              {communityFeedMode === "near_me"
                ? "Enable location services to see reviews near you"
                : "Move the map to explore reviews in different areas"}
            </Text>
          </View>
        ) : null}

        {/* No reviews found in area */}
        {((userLocation && communityFeedMode === "near_me") ||
          (mapCenter && communityFeedMode === "map_area")) &&
        communityReviews.length === 0 &&
        !communityLoading ? (
          <View style={styles.emptyContainer}>
            <Ionicons
              name="chatbubbles-outline"
              size={48}
              color={theme.colors.textLight}
            />
            <Text style={styles.emptyTitle}>
              {t("community.no_reviews_nearby")}
            </Text>
            <Text style={styles.emptyText}>
              Be the first to review a location in this area!
            </Text>
          </View>
        ) : null}

        {/* Safety Updates Section */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Text style={commonStyles.sectionTitle}>
              {t("community.safety_insights")}
            </Text>
            {safetyInsights.length > 0 && (
              <TouchableOpacity
                onPress={() =>
                  notify.info("Full insights view coming soon!", "Coming Soon")
                }
              >
                <Text style={styles.seeAllText}>{t("community.see_all")}</Text>
              </TouchableOpacity>
            )}
          </View>
          {safetyInsightsLoading ? (
            <ActivityIndicator size="small" color={theme.colors.primary} />
          ) : safetyInsights.length > 0 ? (
            safetyInsights.map(renderSafetyInsight)
          ) : (
            <Text style={styles.emptyText}>
              {t("community.no_safety_alerts_at_this_time")}
            </Text>
          )}
        </View>

        {/* Trending Locations Section */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Text style={commonStyles.sectionTitle}>
              Community Awareness This Week
            </Text>
            {/* Only show "See all" if there are trending locations */}
            {trendingLocations.length > 0 && (
              <TouchableOpacity
                onPress={() =>
                  notify.info("Full list view coming soon!", "Coming Soon")
                }
              >
                <Text style={styles.seeAllText}>{t("community.see_all")}</Text>
              </TouchableOpacity>
            )}
          </View>
          {trendingLoading ? (
            <ActivityIndicator size="small" color={theme.colors.primary} />
          ) : trendingLocations.length > 0 ? (
            trendingLocations.map((location, index) =>
              renderTrendingLocation(
                location.location_id || `trending-${index}`,
                location.location_name,
                location.trend_direction,
                location.review_count_current,
              ),
            )
          ) : (
            <Text style={styles.emptyText}>
              No significant activity this week
            </Text>
          )}
        </View>

        {/* Recent Reviews Section */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Text style={commonStyles.sectionTitle}>
              {t("community.recent_reviews")}
            </Text>
          </View>
          {/* Filter Button */}
          <TouchableOpacity
            style={[commonStyles.primaryButton, styles.filterReviewsButton]}
            onPress={() => setFiltersModalVisible(true)}
          >
            <Ionicons
              name="options"
              size={20}
              color={theme.colors.textOnPrimary}
            />
            <Text style={commonStyles.primaryButtonText}>
              {t("community.filter_reviews")}
            </Text>
          </TouchableOpacity>
          {filteredReviews.length > 0 ? (
            filteredReviews.map(renderReviewItem)
          ) : (
            <Text style={styles.emptyText}>
              No reviews yet. Be the first to share your experience!
            </Text>
          )}
        </View>
        <AdBanner />

        {/* Bottom padding 
        <View style={{ height: 20 }} />*/}
      </ScrollView>
      {/* User Profile Modal */}
      <UserProfileModal
        visible={profileModalVisible}
        userId={selectedUserId}
        onClose={() => {
          setProfileModalVisible(false);
          setSelectedUserId(null);
        }}
      />
      {/* Filter Modal */}
      <MapFiltersModal
        visible={filtersModalVisible}
        onClose={() => setFiltersModalVisible(false)}
        filters={communityFilters}
        onApplyFilters={setCommunityFilters}
        showMyReviewsFilter={true}
      />
      <GlobalPremiumPromptModal />
    </SafeAreaView>
  );
}

