              title={t('profile.recently_viewed')}
              icon="eye"
              isExpanded={expandedSections.recentlyViewed}
              onToggle={() => toggleSection("recentlyViewed")}
              onLayout={(y) => {
                sectionPositions.current["recentlyViewed"] = y;
