              onLayout={(y) => {
                sectionPositions.current["settings"] = y;
              }}
            >
              <TouchableOpacity
                style={styles.settingItem}
                onPress={() => router.push("/privacy-settings")}
              >
                <Ionicons
                  name="shield-checkmark"
                  size={24}
                  color={theme.colors.primary}
                />
                <Text style={styles.settingText}>{t('profile.privacy_settings')}</Text>
                <Ionicons
                  name="chevron-forward"
                  size={24}
                  color={theme.colors.textSecondary}
                />
              </TouchableOpacity>

              <TouchableOpacity
                style={styles.settingItem}
                onPress={() => router.push("/notification-settings")}
              >
                <Ionicons
                  name="notifications"
                  size={24}
                  color={theme.colors.primary}
                />
                <Text style={styles.settingText}>{t('profile.notifications')}</Text>
                <Ionicons
                  name="chevron-forward"
                  size={24}
                  color={theme.colors.textSecondary}
                />
              </TouchableOpacity>
              <TouchableOpacity
                style={styles.settingItem}
                onPress={() => router.push("/display-settings")}
              >
                <Ionicons
                  name="color-palette"
                  size={24}
                  color={theme.colors.primary}
                />
                <Text style={styles.settingText}>{t('profile.display_preferences')}</Text>
                <Ionicons
                  name="chevron-forward"
                  size={24}
                  color={theme.colors.textSecondary}
                />
              </TouchableOpacity>
            </CollapsibleSection>
            {/* Account Section */}
            <CollapsibleSection
              title={t('profile.account')}
              icon="person-circle"
              isExpanded={expandedSections.account}
              onToggle={() => toggleSection("account")}
              onLayout={(y) => {
                sectionPositions.current["account"] = y;
              }}
            >
              <TouchableOpacity
                style={styles.accountItem}
                onPress={() => router.push("/edit-profile")}
              >
                <Ionicons
                  name="create"
                  size={24}
                  color={theme.colors.primary}
                />
                <Text style={styles.accountText}>{t('profile.edit_profile')}</Text>
              </TouchableOpacity>

              {profile?.avatar_url && (
                <TouchableOpacity
                  style={styles.accountItem}
                  onPress={handleRemoveProfilePicture}
                >
                  <Ionicons name="image" size={24} color={theme.colors.error} />
                  <Text
                    style={[styles.accountText, { color: theme.colors.error }]}
                  >
                    Remove Profile Picture
                  </Text>
                </TouchableOpacity>
              )}
              {profile?.role === "admin" && (
                <TouchableOpacity
                  style={styles.accountItem}
                  onPress={() => router.push("/admin")}
                >
                  <Ionicons
                    name="shield-checkmark"
                    size={24}
                    color={theme.colors.primary}
                  />
                  <Text style={styles.accountText}>{t('profile.admin_panel')}</Text>
                </TouchableOpacity>
              )}
              <TouchableOpacity
                style={styles.accountItem}
                onPress={handleLogout}
              >
                <Ionicons
                  name="log-out"
                  size={24}
                  color={theme.colors.textSecondary}
                />
                <Text style={styles.accountText}>{t('profile.sign_out')}</Text>
              </TouchableOpacity>
            </CollapsibleSection>
          </ScrollView>
        </View>
      )}
    </SafeAreaView>
  );
}

// Collapsible Section Component
function CollapsibleSection({
  title,
  icon,
  isExpanded,
  onToggle,
  children,
  onLayout,
}: {
  title: string;
  icon: string;
  isExpanded: boolean;
  onToggle: () => void;
  children: React.ReactNode;
  onLayout?: (y: number) => void;
}) {
  return (
    <View
      style={styles.section}
      onLayout={(e) => onLayout?.(e.nativeEvent.layout.y)}
    >
      <TouchableOpacity style={styles.sectionHeader} onPress={onToggle}>
        <View style={styles.sectionHeaderLeft}>
          <Ionicons name={icon as any} size={24} color={theme.colors.primary} />
          <Text style={commonStyles.collapsibleTitle}>{title}</Text>
        </View>
        <Ionicons
          name={isExpanded ? "chevron-up" : "chevron-down"}
          size={24}
          color={theme.colors.textSecondary}
        />
      </TouchableOpacity>
      {isExpanded && <View style={styles.sectionContent}>{children}</View>}
    </View>
  );
}

