import React, { useState, useEffect } from "react";
import { theme } from "src/styles/theme";

import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Platform,
  Modal,
  TouchableWithoutFeedback,
  Keyboard,
} from "react-native";
import { AppTextInput as TextInput } from "../src/components/AppTextInput";

import { useRouter, useLocalSearchParams } from "expo-router";
import { Ionicons } from "@expo/vector-icons";
import DateTimePicker from "@react-native-community/datetimepicker";
import { Picker } from "@react-native-picker/picker";
import { useAppDispatch, useAppSelector } from "src/store/hooks";
import { updateReview } from "src/store/locationsSlice";
import { supabase } from "src/services/supabase";
import { Database } from "src/types/database.types";
import { CreateReviewForm } from "@/types/supabase";
import { requireAuth } from "@/utils/authHelpers";
import { notify } from "@/utils/notificationService";
import { logger } from "@/utils/logger";
import { APP_CONFIG } from "@/config/appConfig";
import { validateVisitDateTime } from "@/utils/dateValidation";
import { useAuth } from "@/providers/AuthProvider";
import { commonStyles } from "@/styles/common";
import { useTranslation } from "react-i18next";

type Review = Database["public"]["Tables"]["reviews"]["Row"];

interface RatingProps {
  label: string;
  value: number;
  onChange: (value: number) => void;
  required?: boolean;
}

const RatingInput: React.FC<RatingProps> = ({
  label,
  value,
  onChange,
  required,
}) => {
  const { t } = useTranslation();
  return (
    <View style={commonStyles.ratingContainer}>
      <Text style={commonStyles.ratingLabel}>
        {label}{" "}
        {required && (
          <Text style={commonStyles.requiredAsterisk}>
            {t("review.unknown")}
          </Text>
        )}
      </Text>
      <View style={commonStyles.stars}>
        {[1, 2, 3, 4, 5].map((star) => (
          <TouchableOpacity key={star} onPress={() => onChange(star)}>
            <Ionicons
              name={star <= value ? "star" : "star-outline"}
              size={32}
              color={
                star <= value ? theme.colors.mixedYellow : theme.colors.border
              }
            />
          </TouchableOpacity>
        ))}
      </View>
    </View>
  );
};

export default function EditReviewScreen() {
  const { t } = useTranslation();

  const router = useRouter();
  const { user } = useAuth();

  useEffect(() => {
    if (!requireAuth(user?.id, "edit reviews")) {
      router.back();
    }
  }, [user]);

  const dispatch = useAppDispatch();
  const { reviewId } = useLocalSearchParams();
  const [showVisitTypePicker, setShowVisitTypePicker] = useState(false);

  const { loading } = useAppSelector((state) => state.locations);

  const [originalReview, setOriginalReview] = useState<Review | null>(null);
  const [loadingReview, setLoadingReview] = useState(true);
  const [visitDateTime, setVisitDateTime] = useState(new Date());
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [showTimePicker, setShowTimePicker] = useState(false);
  const [formData, setFormData] = useState({
    title: "",
    content: "",
    overall_rating: 0,
    safety_rating: 0,
    comfort_rating: 0,
    accessibility_rating: 0,
    service_rating: 0,
    visit_type: "solo",
  });

  useEffect(() => {
    if (reviewId) {
      fetchReviewData();
    }
  }, [reviewId]);

  const fetchReviewData = async () => {
    try {
      const { data: review, error } = await supabase
        .from("reviews")
        .select("*")
        .eq("id", reviewId as string)
        .eq("user_id", user!.id)
        .single();

      if (error) throw error;

      if (review) {
        if (!review.created_at) {
          notify.error(t("review.invalid_review_timestamp"));
          router.back();
          return;
        }

        const hoursSinceCreation =
          (Date.now() - new Date(review.created_at).getTime()) /
          (1000 * 60 * 60);

        if (
          hoursSinceCreation > APP_CONFIG.BUSINESS_RULES.REVIEW_EDIT_TIMEFRAME
        ) {
          notify.error(
            `This review can no longer be edited. Reviews can only be edited within ${APP_CONFIG.BUSINESS_RULES.REVIEW_EDIT_TIMEFRAME} hours of creation.`,
          );
          router.back();
          return;
        }
        setOriginalReview(review);
        setFormData({
          title: review.title,
          content: review.content,
          overall_rating: review.overall_rating,
          safety_rating: review.safety_rating,
          comfort_rating: review.comfort_rating,
          accessibility_rating: review.accessibility_rating || 0,
          service_rating: review.service_rating || 0,
          visit_type: review.visit_type || "solo",
        });

        if (review.visited_at) {
          setVisitDateTime(new Date(review.visited_at));
        }
      }
    } catch (error: any) {
      logger.error("Failed to fetch review:", error);
      notify.error(t("review.failed_to_load_review_data_please_try"));
      router.back();
    } finally {
      setLoadingReview(false);
    }
  };

  const handleSubmit = async () => {
    if (!formData.title.trim()) {
      notify.error(t("review.please_enter_a_title_for_your_review"));
      return;
    }
    if (!formData.content.trim()) {
      notify.error(t("review.please_write_your_review"));
      return;
    }
    if (formData.overall_rating === 0) {
      notify.error(t("review.please_provide_an_overall_rating"));
      return;
    }
    if (formData.safety_rating === 0) {
      notify.error(t("review.please_provide_a_safety_rating"));
      return;
    }
    if (formData.comfort_rating === 0) {
      notify.error(t("review.please_provide_a_comfort_rating"));
      return;
    }

    try {
      const updateData: Partial<CreateReviewForm> = {
        title: formData.title,
        content: formData.content,
        overall_rating: formData.overall_rating,
        safety_rating: formData.safety_rating,
        comfort_rating: formData.comfort_rating,
        accessibility_rating: formData.accessibility_rating || undefined,
        service_rating: formData.service_rating || undefined,
        visited_at: visitDateTime.toISOString(),
        visit_type: formData.visit_type as
          | "solo"
          | "couple"
          | "family"
          | "group"
          | "business",
        location_id: originalReview?.location_id,
      };

      await dispatch(
        updateReview({ id: reviewId as string, ...updateData }),
      ).unwrap();

      notify.confirm(
        "Review Updated",
        "Your review has been successfully updated!",
        [{ text: "OK", onPress: () => router.back() }],
      );
    } catch (error: any) {
      logger.error("Review update error:", error);
      notify.error(
        error?.message || "Failed to update review. Please try again.",
      );
    }
  };

  const handleCancel = () => {
    notify.confirm(
      "Discard Changes",
      "Are you sure you want to discard your changes?",
      [
        { text: "Keep Editing", style: "cancel", onPress: () => {} },
        { text: "Discard", style: "destructive", onPress: () => router.back() },
      ],
    );
  };

  if (!user) {
    return (
      <View style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <Text style={commonStyles.textError}>
            Please log in to edit reviews
          </Text>
          <TouchableOpacity
            style={commonStyles.primaryButton}
            onPress={() => router.push("/(auth)/login")}
          >
            <Text style={commonStyles.primaryButtonText}>
              {t("review.go_to_login")}
            </Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  if (loadingReview) {
    return (
      <View style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <Text style={commonStyles.loadingText}>
            {t("review.loading_review")}
          </Text>
        </View>
      </View>
    );
  }

  if (!originalReview) {
    return (
      <View style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <Text style={commonStyles.textError}>
            Review not found or you don't have permission to edit it
          </Text>
          <TouchableOpacity
            style={commonStyles.primaryButton}
            onPress={() => router.back()}
          >
            <Text style={commonStyles.primaryButtonText}>
              {t("review.go_back")}
            </Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  return (
    <View style={commonStyles.container}>
      <View style={styles.safeTop} />
      <ScrollView
        style={commonStyles.scrollView}
        contentContainerStyle={styles.scrollContent}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
      >
        <TouchableWithoutFeedback onPress={Keyboard.dismiss}>
          <View>
            <View style={commonStyles.header}>
              <TouchableOpacity onPress={handleCancel}>
                <Ionicons name="close" size={24} color={theme.colors.text} />
              </TouchableOpacity>
              <Text style={commonStyles.headerTitle}>
                {t("review.edit_review")}
              </Text>
              <View style={{ width: 24 }} />
            </View>

            <View style={styles.form}>
              {/* Title */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  Review Title{" "}
                  <Text style={commonStyles.requiredAsterisk}>
                    {t("review.unknown")}
                  </Text>
                </Text>
                <TextInput
                  style={commonStyles.input}
                  placeholder={t("review.summarize_your_experience")}
                  value={formData.title}
                  onChangeText={(text) =>
                    setFormData({ ...formData, title: text })
                  }
                  maxLength={100}
                />
              </View>

              {/* Ratings */}
              <RatingInput
                label="Overall Experience"
                value={formData.overall_rating}
                onChange={(value) =>
                  setFormData({ ...formData, overall_rating: value })
                }
                required
              />

              <RatingInput
                label="Safety"
                value={formData.safety_rating}
                onChange={(value) =>
                  setFormData({ ...formData, safety_rating: value })
                }
                required
              />

              <RatingInput
                label="Comfort Level"
                value={formData.comfort_rating}
                onChange={(value) =>
                  setFormData({ ...formData, comfort_rating: value })
                }
                required
              />

              <RatingInput
                label="Accessibility"
                value={formData.accessibility_rating}
                onChange={(value) =>
                  setFormData({ ...formData, accessibility_rating: value })
                }
              />

              <RatingInput
                label="Service Quality"
                value={formData.service_rating}
                onChange={(value) =>
                  setFormData({ ...formData, service_rating: value })
                }
              />

              {/* Review Content */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  Your Review{" "}
                  <Text style={commonStyles.requiredAsterisk}>
                    {t("review.unknown")}
                  </Text>
                </Text>
                <TextInput
                  style={[commonStyles.input, commonStyles.textArea]}
                  placeholder={t(
                    "review.share_your_experience_at_this_location",
                  )}
                  value={formData.content}
                  onChangeText={(text) =>
                    setFormData({ ...formData, content: text })
                  }
                  multiline
                  numberOfLines={6}
                  textAlignVertical="top"
                  maxLength={1000}
                />
                <Text style={commonStyles.captionText}>
                  {formData.content.length}/1000
                </Text>
              </View>

              {/* Visit Details */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_date")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowDatePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {visitDateTime.toLocaleDateString()}
                  </Text>
                  <Ionicons
                    name="calendar"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>
              {showDatePicker && (
                <DateTimePicker
                  value={visitDateTime}
                  mode="date"
                  display="default"
                  maximumDate={new Date()}
                  onChange={(event, selectedDate) => {
                    setShowDatePicker(Platform.OS === "ios");
                    if (selectedDate) {
                      const newDateTime = new Date(visitDateTime);
                      newDateTime.setHours(selectedDate.getHours());
                      newDateTime.setMinutes(selectedDate.getMinutes());

                      // Check if the combined date+time is in the future
                      const result = validateVisitDateTime(newDateTime);
                      if (!result.isValid) {
                        notify.error(result.errorMessage || "Invalid date");
                      }
                      setVisitDateTime(result.validatedDate);
                    }
                  }}
                />
              )}
              {showTimePicker && (
                <DateTimePicker
                  value={visitDateTime}
                  mode="time"
                  display="default"
                  onChange={(event, selectedDate) => {
                    setShowTimePicker(false);
                    if (selectedDate) {
                      const newDateTime = new Date(visitDateTime);
                      newDateTime.setHours(selectedDate.getHours());
                      newDateTime.setMinutes(selectedDate.getMinutes());

                      // Check if the combined date+time is in the future
                      const result = validateVisitDateTime(newDateTime);
                      if (!result.isValid) {
                        notify.error(result.errorMessage || "Invalid date");
                      }
                      setVisitDateTime(result.validatedDate);
                    }
                  }}
                />
              )}

              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_time")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowTimePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {visitDateTime.toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </Text>
                  <Ionicons
                    name="time"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>

              {showTimePicker && (
                <DateTimePicker
                  value={visitDateTime}
                  mode="time"
                  display="default"
                  onChange={(event, selectedTime) => {
                    setShowTimePicker(false);
                    if (selectedTime) {
                      const newDateTime = new Date(visitDateTime);
                      newDateTime.setHours(selectedTime.getHours());
                      newDateTime.setMinutes(selectedTime.getMinutes());

                      // Check if the combined date+time is in the future
                      if (newDateTime > new Date()) {
                        notify.error(
                          t("review.visit_time_cannot_be_in_the_future"),
                        );
                        const now = new Date();
                        newDateTime.setHours(now.getHours());
                        newDateTime.setMinutes(now.getMinutes());
                      }

                      setVisitDateTime(newDateTime);
                    }
                  }}
                />
              )}

              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_type")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowVisitTypePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {formData.visit_type.charAt(0).toUpperCase() +
                      formData.visit_type.slice(1)}
                  </Text>
                  <Ionicons
                    name="chevron-down"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>

              {/* Visit Type Picker Modal */}
              <Modal
                visible={showVisitTypePicker}
                transparent={true}
                animationType="slide"
                onRequestClose={() => setShowVisitTypePicker(false)}
              >
                <View style={commonStyles.modalOverlay}>
                  <View style={commonStyles.modalContent}>
                    <View style={commonStyles.modalHeader}>
                      <Text style={commonStyles.modalTitle}>
                        {t("review.visit_type")}
                      </Text>
                      <TouchableOpacity
                        onPress={() => setShowVisitTypePicker(false)}
                      >
                        <Text style={commonStyles.modalDone}>
                          {t("review.done")}
                        </Text>
                      </TouchableOpacity>
                    </View>
                    <Picker
                      selectedValue={formData.visit_type}
                      onValueChange={(value) =>
                        setFormData({ ...formData, visit_type: value })
                      }
                      style={styles.picker}
                      itemStyle={styles.pickerItem}
                    >
                      <Picker.Item label="Solo" value="solo" />
                      <Picker.Item label="Couple" value="couple" />
                      <Picker.Item label="Family" value="family" />
                      <Picker.Item label="Group" value="group" />
                      <Picker.Item label="Business" value="business" />
                    </Picker>
                  </View>
                </View>
              </Modal>

              {/* Action Buttons */}
              <View style={styles.buttonGroup}>
                <TouchableOpacity
                  style={[
                    commonStyles.primaryButton,
                    commonStyles.cancelButton,
                  ]}
                  onPress={handleCancel}
                >
                  <Text style={commonStyles.cancelButtonText}>
                    {t("review.cancel")}
                  </Text>
                </TouchableOpacity>

                <TouchableOpacity
                  style={[
                    commonStyles.primaryButton,
                    loading && commonStyles.buttonDisabled,
                  ]}
                  onPress={handleSubmit}
                  disabled={loading}
                >
                  <Text style={commonStyles.primaryButtonText}>
                    {loading ? "Updating..." : "Update Review"}
                  </Text>
                </TouchableOpacity>
              </View>
            </View>
          </View>
        </TouchableWithoutFeedback>
      </ScrollView>
    </View>
  );
}

const styles = StyleSheet.create({
  safeTop: {
    height: Platform.OS === "ios" ? 44 : 0,
