import React, { useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { theme } from "@/styles/theme";
import { supabase } from "@/services/supabase";
import { useAuth } from "@/providers/AuthProvider";
import { notify } from "@/utils/notificationService";
import { logger } from "@/utils/logger";
import { IubendaDocument } from "@/components/IubendaDocument";
import { recordLegalAcceptance } from "@/services/consentService";
import { commonStyles } from "@/styles/common";
import { useTranslation } from "react-i18next";

const IUBENDA_PUBLIC_ID = "69238085";

export default function LegalAcceptanceScreen() {
  const { t } = useTranslation();
  const { user, refreshOnboardingStatus } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [termsChecked, setTermsChecked] = useState(false);
  const [privacyChecked, setPrivacyChecked] = useState(false);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [showTerms, setShowTerms] = useState(false);

  const canContinue = termsChecked && privacyChecked;

  const handleAccept = async () => {
    if (!user?.id || !canContinue) return;

    setIsLoading(true);
    try {
      const { error } = await supabase
        .from("profiles")
        .update({ terms_accepted_at: new Date().toISOString() })
        .eq("user_id", user.id);

      if (error) throw error;

      recordLegalAcceptance().catch((err) =>
        logger.error("=== IUBENDA ERROR ===", err),
      );
      await refreshOnboardingStatus();
    } catch (error) {
      logger.error("Failed to save terms acceptance:", error);
      notify.error(t("legal.something_went_wrong_please_try_again"));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <SafeAreaView style={commonStyles.container}>
      <ScrollView contentContainerStyle={styles.content}>
        <View style={styles.iconContainer}>
          <Ionicons
            name="document-text"
            size={64}
            color={theme.colors.primary}
          />
        </View>
        <Text style={styles.title}>{t("legal.terms_privacy")}</Text>
        <Text style={styles.subtitle}>
          Please review and accept our terms to continue
        </Text>

        <View style={styles.checkboxContainer}>
          <TouchableOpacity
            style={styles.checkboxRow}
            onPress={() => setTermsChecked(!termsChecked)}
            activeOpacity={0.7}
          >
            <View
              style={[styles.checkbox, termsChecked && styles.checkboxChecked]}
            >
              {termsChecked && (
                <Ionicons
                  name="checkmark"
                  size={18}
                  color={theme.colors.textOnPrimary}
                />
              )}
            </View>
            <Text style={styles.checkboxLabel}>
              I agree to the{" "}
              <Text
                style={commonStyles.textPrimaryLink}
                onPress={() => setShowTerms(true)}
              >
                Terms of Service
              </Text>
            </Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={styles.checkboxRow}
            onPress={() => setPrivacyChecked(!privacyChecked)}
            activeOpacity={0.7}
          >
            <View
              style={[
                styles.checkbox,
                privacyChecked && styles.checkboxChecked,
              ]}
            >
              {privacyChecked && (
                <Ionicons
                  name="checkmark"
                  size={18}
                  color={theme.colors.textOnPrimary}
                />
              )}
            </View>
            <Text style={styles.checkboxLabel}>
              I have read the{" "}
              <Text
                style={commonStyles.textPrimaryLink}
                onPress={() => setShowPrivacy(true)}
              >
                Privacy Policy
              </Text>
            </Text>
          </TouchableOpacity>
        </View>

        <View style={styles.infoBox}>
          <Ionicons
            name="shield-checkmark"
            size={24}
            color={theme.colors.primary}
          />
          <Text style={styles.infoText}>
            Your privacy matters. We only collect data necessary to provide
            personalized safety recommendations. You control what demographic
            information you share.
          </Text>
        </View>
      </ScrollView>

      <View style={commonStyles.footer}>
        <TouchableOpacity
          style={[
            commonStyles.primaryButton,
            !canContinue && commonStyles.buttonDisabled,
          ]}
          onPress={handleAccept}
          disabled={!canContinue || isLoading}
          activeOpacity={0.8}
        >
          {isLoading ? (
            <ActivityIndicator color={theme.colors.textOnPrimary} />
          ) : (
            <Text style={commonStyles.primaryButtonText}>
              {t("legal.continue")}
            </Text>
          )}
        </TouchableOpacity>
      </View>

      <IubendaDocument
        type="privacy-policy"
        publicId={IUBENDA_PUBLIC_ID}
        visible={showPrivacy}
        onClose={() => setShowPrivacy(false)}
        title={t("legal.privacy_policy")}
      />

      <IubendaDocument
        type="terms-and-conditions"
        publicId={IUBENDA_PUBLIC_ID}
        visible={showTerms}
        onClose={() => setShowTerms(false)}
        title={t("legal.terms_of_service")}
      />
    </SafeAreaView>
  );
}

