import React, { useEffect, useState } from "react";
import {
  View,
  Text,
  StyleSheet,
  ScrollView,
  TouchableOpacity,
  Modal,
  Share,
  Platform,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { router } from "expo-router";
import { MaterialIcons } from "@expo/vector-icons";
import { theme } from "../src/styles/theme";
import SettingToggle from "../src/components/SettingToggle";
import { useAppSelector } from "../src/store/hooks";
import { ActivityIndicator } from "react-native";
import { updateUserProfile } from "../src/store/userSlice";
import { supabase } from "@/services/supabase";
import { useAppDispatch } from "../src/store/hooks";
import { useAuth } from "@/providers/AuthProvider";
import { fetchRecentReviews } from "@/store/locationsSlice";
import { notify } from "@/utils/notificationService";
import { logger } from "@/utils/logger";
import { IubendaDocument } from "@/components/IubendaDocument";
import { commonStyles } from "@/styles/common";
import { useTranslation } from "react-i18next";

export default function PrivacySettings() {
  const { t } = useTranslation();

  const { user, signOut } = useAuth();
  const profile = useAppSelector((state: any) => state.user.profile);
  const userLocation = useAppSelector((state) => state.locations.userLocation);

  const [showDemographics, setShowDemographics] = useState(false);
  const [profileVisibility, setProfileVisibility] = useState(false);
  const [loading, setLoading] = useState(true);
  const [viewDataModalVisible, setViewDataModalVisible] = useState(false);
  const [deleteConfirmVisible, setDeleteConfirmVisible] = useState(false);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [showTerms, setShowTerms] = useState(false);
  const IUBENDA_PUBLIC_ID = "69238085";
  const [activityStats, setActivityStats] = useState<{
    review_count: number;
    route_count: number;
  } | null>(null);
  const [loadingStats, setLoadingStats] = useState(false);

  const dispatch = useAppDispatch();

  useEffect(() => {
    if (profile) {
      setShowDemographics(profile.show_demographics ?? true);
      setProfileVisibility(profile.privacy_level === "public");
      setLoading(false);
    }
  }, [profile]);

  useEffect(() => {
    if (viewDataModalVisible) {
      fetchActivityStats();
    }
  }, [viewDataModalVisible]);

  const savePrivacySetting = async (field: string, value: any) => {
    if (!user) return;
    try {
      await dispatch(
        updateUserProfile({
          userId: user.id,
          profileData: { [field]: value },
        }),
      ).unwrap();

      // NEW: Reload community reviews after privacy change
      if (field === "show_demographics" && userLocation) {
        dispatch(
          fetchRecentReviews({
            latitude: userLocation.latitude,
            longitude: userLocation.longitude,
          }),
        );
      }
    } catch (error) {
      notify.error(t("settings.failed_to_save_setting_please_try_again"));
    }
  };

  const fetchActivityStats = async () => {
    if (!user?.id) return;

    setLoadingStats(true);
    try {
      const { data, error } = await supabase.rpc("get_user_activity_stats", {
        p_user_id: user.id,
      });

      if (error) {
        logger.error("Error fetching activity stats:", error);
        return;
      }

      if (data && data.length > 0) {
        setActivityStats(data[0]);
      }
    } catch (error) {
      logger.error("Exception fetching activity stats:", error);
    } finally {
      setLoadingStats(false);
    }
  };

  const handleExportData = async () => {
    if (!user) return;
    try {
      // Fetch user's reviews with location details
      const { data: reviews, error: reviewsError } = await supabase
        .from("reviews")
        .select(
          `
        id,
        title,
        content,
        overall_rating,
        safety_rating,
        comfort_rating,
        accessibility_rating,
        service_rating,
        visit_type,
        created_at,
        updated_at,
        visited_at,
        locations (
          name,
          address
        )
      `,
        )
        .eq("user_id", user.id)
        .eq("status", "active")
        .order("created_at", { ascending: false });

      if (reviewsError) {
        logger.error("Error fetching reviews for export:", reviewsError);
      }

      // Fetch user's routes
      const { data: routes, error: routesError } = await supabase
        .from("routes")
        .select("*")
        .eq("user_id", user?.id)
        .order("created_at", { ascending: false });

      if (routesError) {
        logger.error("Error fetching routes for export:", routesError);
      }

      // Format reviews for export
      const formattedReviews =
        reviews?.map((review) => ({
          review_id: review.id,
          location_name: review.locations?.name || "Unknown",
          location_address: review.locations?.address || "",
          title: review.title,
          content: review.content,
          ratings: {
            overall: review.overall_rating,
            safety: review.safety_rating,
            comfort: review.comfort_rating,
            accessibility: review.accessibility_rating,
            service: review.service_rating,
          },
          visit_type: review.visit_type,
          created_at: review.created_at,
          updated_at: review.updated_at,
          visited_at: review.visited_at,
        })) || [];

      // Format routes for export
      const formattedRoutes =
        routes?.map((route) => ({
          route_id: route.id,
          origin: route.origin_name,
          destination: route.destination_name,
          distance_km: route.distance_km,
          duration_minutes: route.duration_minutes,
          safety_score: route.safety_score,
          waypoints_count: Array.isArray(route.route_coordinates)
            ? route.route_coordinates.length
            : 0,
          created_at: route.created_at,
          navigation_started: route.navigation_started_at,
          navigation_completed: route.navigation_ended_at,
        })) || [];

      // Gather all user data including reviews and routes
      const exportData = {
        account: {
          email: user?.email,
          created_at: user?.created_at,
          id: user?.id,
        },
        profile: {
          full_name: profile?.full_name,
          race_ethnicity: profile?.race_ethnicity,
          gender: profile?.gender,
          lgbtq_status: profile?.lgbtq_status,
          religion: profile?.religion,
          age_range: profile?.age_range,
          disability_status: profile?.disability_status,
          privacy_level: profile?.privacy_level,
          show_demographics: profile?.show_demographics,
        },
        activity: {
          total_reviews: formattedReviews.length,
          total_routes_planned: formattedRoutes.length,
        },
        reviews: formattedReviews,
        routes: formattedRoutes,
        privacy_settings: {
          demographics_visible: showDemographics,
          profile_public: profileVisibility,
        },
        export_date: new Date().toISOString(),
        note: "This is all the data TruGuide has collected about you.",
      };

      const jsonString = JSON.stringify(exportData, null, 2);

      // Create filename from email or user ID
      const username = user?.email?.split("@")[0] || `user_${user?.id}`;
      const filename = `safepath_data_${username}.json`;

      // For iOS/Android, the Share API will show the filename in some contexts
      if (Platform.OS === "ios") {
        await Share.share(
          {
            message: `${filename}\n\n${jsonString}`,
            title: filename,
          },
          {
            subject: filename,
            dialogTitle: `Export ${filename}`,
          },
        );
      } else {
        await Share.share(
          {
            message: jsonString,
            title: filename,
          },
          {
            subject: filename,
            dialogTitle: `Export ${filename}`,
          },
        );
      }
    } catch (error) {
      notify.error(t("settings.failed_to_export_data_please_try_again"));
      logger.error("Export error:", error);
    }
  };

  const handleDeleteAccount = async () => {
    try {
      setDeleteConfirmVisible(false);

      const {
        data: { session },
      } = await supabase.auth.getSession();

      if (!session) {
        notify.error(t("settings.you_must_be_logged_in_to_delete_your"));
        return;
      }

      const url = `${process.env.EXPO_PUBLIC_SUPABASE_URL}/functions/v1/delete-user-account`;

      const response = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${session.access_token}`,
          "Content-Type": "application/json",
        },
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || "Failed to delete account");
      }

      // Rest of success handling...
      await signOut();

      notify.confirm(
        "Account Deleted",
        "Your account has been permanently deleted.",
        [{ text: "OK", onPress: () => router.replace("/welcome") }],
      );
    } catch (error) {
      logger.error("=== DELETE ERROR ===", error);
      notify.error(`Failed to delete account: `);
    }
  };

  if (loading) {
    return (
      <SafeAreaView style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <ActivityIndicator size="large" color={theme.colors.primary} />
        </View>
      </SafeAreaView>
    );
  }
  return (
    <SafeAreaView style={commonStyles.container}>
      {/* Header */}
      <View style={commonStyles.header}>
        <TouchableOpacity
          onPress={() => router.back()}
          style={[commonStyles.backButton]}
        >
          <MaterialIcons
            name="arrow-back"
            size={28}
            style={commonStyles.backButtonText}
          />
        </TouchableOpacity>
        <Text style={commonStyles.headerTitle}>
          {t("settings.privacy_settings")}
        </Text>
        <View style={commonStyles.headerPlaceholder} />
      </View>

      <ScrollView style={styles.content}>
        <Text style={commonStyles.sectionTitle}>
          {t("settings.demographic_privacy")}
        </Text>

        <SettingToggle
          label="Show demographics on reviews"
          description="Display your demographic information when you post reviews"
          value={showDemographics}
          onToggle={async () => {
            const newValue = !showDemographics;
            setShowDemographics(newValue);
            await savePrivacySetting("show_demographics", newValue);
          }}
        />

        <Text style={[commonStyles.sectionTitle, styles.sectionTitleSpaced]}>
          Profile Privacy
        </Text>

        <SettingToggle
          label="Public profile"
          description="Allow other users to view your profile and travel statistics"
          value={profileVisibility}
          onToggle={async () => {
            const newValue = !profileVisibility;
            setProfileVisibility(newValue);
            await savePrivacySetting(
              "privacy_level",
              newValue ? "public" : "private",
            );
          }}
        />
        {/* Legal Documents Section */}
        <Text style={[commonStyles.sectionTitle, styles.sectionTitleSpaced]}>
          Legal Documents
        </Text>

        <TouchableOpacity
          style={styles.actionButton}
          onPress={() => setShowTerms(true)}
        >
          <MaterialIcons
            name="description"
            size={24}
            color={theme.colors.text}
          />
          <View style={styles.actionTextContainer}>
            <Text style={styles.actionTitle}>
              {t("settings.terms_of_service")}
            </Text>
            <Text style={styles.actionDescription}>
              View our terms and conditions
            </Text>
          </View>
          <MaterialIcons
            name="chevron-right"
            size={24}
            color={theme.colors.text}
          />
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.actionButton}
          onPress={() => setShowPrivacy(true)}
        >
          <MaterialIcons
            name="privacy-tip"
            size={24}
            color={theme.colors.text}
          />
          <View style={styles.actionTextContainer}>
            <Text style={styles.actionTitle}>
              {t("settings.privacy_policy")}
            </Text>
            <Text style={styles.actionDescription}>
              View how we handle your data
            </Text>
          </View>
          <MaterialIcons
            name="chevron-right"
            size={24}
            color={theme.colors.text}
          />
        </TouchableOpacity>

        {/* Account Management Section */}
        <Text style={[commonStyles.sectionTitle, styles.sectionTitleSpaced]}>
          Account Management
        </Text>

        <TouchableOpacity
          style={styles.actionButton}
          onPress={() => setViewDataModalVisible(true)}
        >
          <MaterialIcons name="folder" size={24} color={theme.colors.text} />
          <View style={styles.actionTextContainer}>
            <Text style={styles.actionTitle}>{t("settings.view_my_data")}</Text>
            <Text style={styles.actionDescription}>
              See what information TruGuide has collected
            </Text>
          </View>
          <MaterialIcons
            name="chevron-right"
            size={24}
            color={theme.colors.text}
          />
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.actionButton}
          onPress={handleExportData}
        >
          <MaterialIcons
            name="download"
            size={24}
            color={theme.colors.primary}
          />
          <View style={styles.actionTextContainer}>
            <Text style={styles.actionTitle}>
              {t("settings.export_my_data")}
            </Text>
            <Text style={styles.actionDescription}>
              Download all your data in JSON format
            </Text>
          </View>
          <MaterialIcons
            name="chevron-right"
            size={24}
            color={theme.colors.text}
          />
        </TouchableOpacity>

        <TouchableOpacity
          style={styles.dangerButton}
          onPress={() => {
            setDeleteConfirmVisible(true);
          }}
        >
          <MaterialIcons
            name="delete-forever"
            size={24}
            color={theme.colors.error}
          />
          <View style={styles.actionTextContainer}>
            <Text style={[styles.actionTitle, styles.dangerText]}>
              Delete Account
            </Text>
            <Text style={styles.actionDescription}>
              Permanently delete your account and all data
            </Text>
          </View>
          <MaterialIcons
            name="chevron-right"
            size={24}
            color={theme.colors.text}
          />
        </TouchableOpacity>
      </ScrollView>
      {/* View Data Modal */}
      <Modal
        visible={viewDataModalVisible}
        animationType="slide"
        presentationStyle="pageSheet"
      >
        <SafeAreaView style={styles.modalContainer}>
          <View style={commonStyles.modalHeader}>
            <Text style={commonStyles.modalTitle}>{t("settings.my_data")}</Text>
            <TouchableOpacity onPress={() => setViewDataModalVisible(false)}>
              <MaterialIcons name="close" size={28} color={theme.colors.text} />
            </TouchableOpacity>
          </View>

          <ScrollView style={commonStyles.modalContent}>
            <Text style={styles.dataSection}>
              {t("settings.profile_information")}
            </Text>
            <Text style={styles.dataText}>Email: {user?.email}</Text>
            <Text style={styles.dataText}>
              Name: {profile?.full_name || "Not set"}
            </Text>
            <Text style={styles.dataText}>
              Account Created:
              {new Date(profile.created_at).toLocaleDateString()}
            </Text>
            <Text style={styles.dataSection}>
              {t("settings.demographic_data")}
            </Text>
            <Text style={styles.dataText}>
              Race/Ethnicity: {profile?.race_ethnicity?.join(", ") || "Not set"}
            </Text>
            <Text style={styles.dataText}>
              Gender: {profile?.gender || "Not set"}
            </Text>
            <Text style={styles.dataText}>
              LGBTQ+: {profile?.lgbtq_status ? "Yes" : "No"}
            </Text>
            <Text style={styles.dataText}>
              Religion: {profile?.religion || "Not set"}
            </Text>
            <Text style={styles.dataText}>
              Age Range: {profile?.age_range || "Not set"}
            </Text>
            <Text style={styles.dataText}>
              Disability Status:
              {profile?.disability_status?.join(", ") || "None"}
            </Text>
            <Text style={styles.dataSection}>
              {t("settings.privacy_settings")}
            </Text>
            <Text style={styles.dataText}>
              Privacy Level: {profile?.privacy_level || "public"}
            </Text>
            <Text style={styles.dataText}>
              Show Demographics: {profile?.show_demographics ? "Yes" : "No"}
            </Text>
            <Text style={styles.dataSection}>{t("settings.activity")}</Text>
            {loadingStats ? (
              <ActivityIndicator size="small" color={theme.colors.primary} />
            ) : activityStats ? (
              <>
                <Text style={styles.dataText}>
                  Reviews Posted: {activityStats.review_count}
                </Text>
                <Text style={styles.dataText}>
                  Routes Planned: {activityStats.route_count}
                </Text>
              </>
            ) : (
              <>
                <Text style={styles.dataText}>
                  {t("settings.reviews_posted_0")}
                </Text>
                <Text style={styles.dataText}>
                  {t("settings.routes_planned_0")}
                </Text>
              </>
            )}
          </ScrollView>
        </SafeAreaView>
      </Modal>
      {/* Delete Confirmation Modal */}
      <Modal visible={deleteConfirmVisible} transparent animationType="fade">
        <View style={commonStyles.modalOverlay}>
          <View style={styles.deleteModal}>
            <MaterialIcons
              name="warning"
              size={48}
              color={theme.colors.error}
            />
            <Text style={styles.deleteTitle}>
              {t("settings.delete_account")}
            </Text>
            <Text style={styles.deleteMessage}>
              This will permanently delete your account and all associated data
              including your profile, reviews, and settings.
              {"\n\n"}This action cannot be undone.
            </Text>
            <View style={styles.deleteButtons}>
              <TouchableOpacity
                style={styles.cancelButton}
                onPress={() => setDeleteConfirmVisible(false)}
              >
                <Text style={styles.cancelButtonText}>
                  {t("settings.cancel")}
                </Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={styles.confirmDeleteButton}
                onPress={() => {
                  handleDeleteAccount();
                }}
              >
                <Text style={styles.confirmDeleteText}>
                  {t("settings.delete_forever")}
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </Modal>
      <IubendaDocument
        type="privacy-policy"
        publicId={IUBENDA_PUBLIC_ID}
        visible={showPrivacy}
        onClose={() => setShowPrivacy(false)}
        title={t("settings.privacy_policy")}
      />

      <IubendaDocument
        type="terms-and-conditions"
        publicId={IUBENDA_PUBLIC_ID}
        visible={showTerms}
        onClose={() => setShowTerms(false)}
        title={t("settings.terms_of_service")}
      />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  deleteModal: {
    backgroundColor: theme.colors.card,
    borderRadius: 12,
    padding: theme.spacing.xl,
    width: "100%",
    maxWidth: 400,
    alignItems: "center",
  },
  deleteTitle: {
    fontSize: 22,
    fontWeight: "bold",
    color: theme.colors.text,
    marginTop: theme.spacing.md,
    marginBottom: theme.spacing.sm,
  },
  deleteMessage: {
    fontSize: 15,
    color: theme.colors.textSecondary,
    textAlign: "center",
    lineHeight: 22,
    marginBottom: theme.spacing.xl,
  },
  deleteButtons: {
    flexDirection: "row",
    gap: theme.spacing.md,
    width: "100%",
  },
