import React, { useEffect, useState } from "react";
import { theme } from "src/styles/theme";

import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  Platform,
  Modal,
  TouchableWithoutFeedback,
  Keyboard,
} from "react-native";
import { AppTextInput as TextInput } from "../src/components/AppTextInput";

import { Picker } from "@react-native-picker/picker";
import { useRouter, useLocalSearchParams } from "expo-router";
import { useAppDispatch, useAppSelector } from "src/store/hooks";
import { submitReview } from "src/store/locationsSlice";
import { Ionicons } from "@expo/vector-icons";
import DateTimePicker from "@react-native-community/datetimepicker";
import {
  createLocationFromSearch,
  setUserLocation,
} from "src/store/locationsSlice";
import { requireAuth } from "@/utils/authHelpers";
import { notify } from "@/utils/notificationService";
import { logger } from "@/utils/logger";
import { validateVisitDateTime } from "@/utils/dateValidation";
import { useAuth } from "@/providers/AuthProvider";
import { commonStyles } from "@/styles/common";
import { showInterstitialWithCooldown } from "@/services/adMobService";
import { useTranslation } from "react-i18next";
interface RatingProps {
  label: string;
  value: number;
  onChange: (value: number) => void;
  required?: boolean;
}

const RatingInput: React.FC<RatingProps> = ({
  label,
  value,
  onChange,
  required,
}) => {
  const { t } = useTranslation();

  return (
    <View style={commonStyles.ratingContainer}>
      <Text style={commonStyles.ratingLabel}>
        {label}{" "}
        {required && (
          <Text style={commonStyles.requiredAsterisk}>
            {t("review.unknown")}
          </Text>
        )}
      </Text>
      <View style={commonStyles.stars}>
        {[1, 2, 3, 4, 5].map((star) => (
          <TouchableOpacity key={star} onPress={() => onChange(star)}>
            <Ionicons
              name={star <= value ? "star" : "star-outline"}
              size={32}
              color={
                star <= value ? theme.colors.mixedYellow : theme.colors.border
              }
            />
          </TouchableOpacity>
        ))}
      </View>
    </View>
  );
};

export default function ReviewScreen() {
  const { t } = useTranslation();

  const router = useRouter();
  const dispatch = useAppDispatch();
  const { locationId, locationName, locationData, isNewLocation } =
    useLocalSearchParams();
  const typedLocationId = locationId as string | undefined;
  const typedLocationData = locationData as string | undefined;
  const typedIsNewLocation = isNewLocation as string | undefined;
  const [showVisitTypePicker, setShowVisitTypePicker] = useState(false);

  const { loading } = useAppSelector((state) => state.locations);
  const { user } = useAuth();
  useEffect(() => {
    requireAuth(user?.id, "write reviews");
  }, [user]);

  const [visitDateTime, setVisitDateTime] = useState(new Date());
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [showTimePicker, setShowTimePicker] = useState(false);
  const [formData, setFormData] = useState({
    title: "",
    content: "",
    overall_rating: 0,
    safety_rating: 0,
    comfort_rating: 0,
    accessibility_rating: 0,
    service_rating: 0,
    visit_type: "solo" as const,
  });
  const parsedLocationData = typedLocationData
    ? JSON.parse(typedLocationData)
    : null;
  const isCreatingNew = typedIsNewLocation === "true";
  const [currentLocationId, setCurrentLocationId] = useState<string | null>(
    isCreatingNew ? null : typedLocationId || null,
  );
  const [editableLocationName, setEditableLocationName] = useState("");
  useEffect(() => {
    if (!isCreatingNew && !typedLocationId) {
      notify.error(t("review.no_location_specified"));
      router.back();
      return;
    }

    if (isCreatingNew && !parsedLocationData) {
      notify.error(t("review.no_location_data_provided"));
      router.back();
      return;
    }
  }, [typedLocationId, isCreatingNew, parsedLocationData]);

  const handleSubmit = async () => {
    requireAuth(user?.id, "write reviews");

    // Validation
    if (!formData.title.trim()) {
      notify.error(t("review.please_enter_a_review_title"));
      return;
    }

    if (isCreatingNew && !editableLocationName.trim()) {
      notify.error(t("review.please_enter_a_name_for_this_location"));
      return;
    }

    if (!formData.content.trim()) {
      notify.error(t("review.please_enter_review_content"));
      return;
    }

    if (!formData.overall_rating || !formData.safety_rating) {
      notify.error(t("review.please_provide_both_overall_and_safety"));
      return;
    }

    let finalLocationId = currentLocationId;
    // NOTE: Despite the "mapbox" naming, this actually uses Google Geocoding API

    try {
      // If this is a new location, create it first
      if (isCreatingNew && parsedLocationData) {
        // Convert parsed data to SearchLocation format
        const searchLocation = {
          id: `temp-${Date.now()}`, // Temporary ID
          name: editableLocationName.trim(),
          address: parsedLocationData.address,
          latitude: parsedLocationData.latitude,
          longitude: parsedLocationData.longitude,
          place_type: parsedLocationData.place_type,
          source: "mapbox" as const,
        };

        // Create the location
        finalLocationId = await dispatch(
          createLocationFromSearch({ searchLocation, userId: user!.id }),
        ).unwrap();
        setCurrentLocationId(finalLocationId);

        dispatch(
          setUserLocation({
            latitude: parsedLocationData.latitude,
            longitude: parsedLocationData.longitude,
          }),
        );
      }
      if (!finalLocationId) {
        throw new Error("No location ID available for review submission");
      }

      if (!finalLocationId) {
        throw new Error("No location ID available for review submission");
      }

      // Now submit the review with the location ID
      const reviewData = {
        location_id: finalLocationId,
        ...formData,
        visited_at: visitDateTime.toISOString(),
        accessibility_rating: formData.accessibility_rating || undefined,
        service_rating: formData.service_rating || undefined,
      };

      const result = await dispatch(submitReview(reviewData)).unwrap();
      if (result && "queued" in result) {
        notify.success(t("review.review_saved_will_sync_when_online"));
      } else {
        notify.success(t("review.review_submitted_successfully"));
      }
      notify.confirm("Success", "Review submitted successfully!", [
        {
          text: "OK",
          onPress: () => {
            showInterstitialWithCooldown();
            if (isCreatingNew && finalLocationId) {
              // Pass the real location ID back
              router.replace({
                pathname: "/(tabs)",
                params: {
                  tab: "map",
                  openLocationId: finalLocationId,
                  refresh: Date.now().toString(),
                },
              });
            } else {
              router.back();
            }
          },
        },
      ]);
    } catch (error: any) {
      logger.error("🚨 Review submission error:", error);

      if (error.code === "23505") {
        notify.success(
          "You have already reviewed this location. You can edit your existing review instead.",
          "Already Reviewed",
        );
        return;
      }

      notify.error(
        "Error",
        error?.message || "Failed to submit review. Please try again.",
      );
    }
  };

  if (!user) {
    return (
      <View style={commonStyles.container}>
        <View style={commonStyles.centerContainer}>
          <Text style={commonStyles.textError}>
            Please log in to submit a review
          </Text>
          <TouchableOpacity
            style={commonStyles.primaryButton}
            onPress={() => router.push("/(auth)/login")}
          >
            <Text style={commonStyles.primaryButtonText}>
              {t("review.go_to_login")}
            </Text>
          </TouchableOpacity>
        </View>
      </View>
    );
  }

  return (
    <View style={commonStyles.container}>
      <View style={styles.safeTop} />
      <ScrollView
        style={commonStyles.scrollView}
        contentContainerStyle={styles.scrollContent}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
      >
        <TouchableWithoutFeedback onPress={Keyboard.dismiss}>
          <View>
            <View style={commonStyles.header}>
              <TouchableOpacity
                onPress={() => router.back()}
                style={commonStyles.backButton}
              >
                <Ionicons
                  name="arrow-back"
                  size={28}
                  style={commonStyles.backButtonText}
                />
              </TouchableOpacity>
              <Text style={commonStyles.headerTitle}>
                {t("review.write_a_review")}
              </Text>
              <View style={{ width: 24 }} />
            </View>

            <View style={styles.locationInfo}>
              <Text style={styles.locationName}>
                {locationName || "Location"}
              </Text>
            </View>

            {/* Location Name for New Locations */}
            {isCreatingNew && (
              <View style={styles.newLocationSection}>
                <View style={commonStyles.formField}>
                  <Text style={commonStyles.formLabel}>
                    📍 What is this place called?
                    <Text style={commonStyles.requiredAsterisk}>
                      {t("review.unknown")}
                    </Text>
                  </Text>
                  <TextInput
                    style={commonStyles.input}
                    placeholder='e.g., "Joe&apos;s Pizza" or "Central Park"'
                    value={editableLocationName}
                    onChangeText={setEditableLocationName}
                    maxLength={100}
                    autoCapitalize="words"
                  />
                  <Text style={styles.helperText}>
                    Give this location a name so others can find it
                  </Text>
                </View>
              </View>
            )}

            <View style={styles.form}>
              {/* Title */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  Review Title{" "}
                  <Text style={commonStyles.requiredAsterisk}>
                    {t("review.unknown")}
                  </Text>
                </Text>
                <TextInput
                  style={commonStyles.input}
                  placeholder={t("review.summarize_your_experience")}
                  value={formData.title}
                  onChangeText={(text) =>
                    setFormData({ ...formData, title: text })
                  }
                  maxLength={100}
                />
              </View>
              {/* Ratings */}
              <RatingInput
                label="Overall Experience"
                value={formData.overall_rating}
                onChange={(value) =>
                  setFormData({ ...formData, overall_rating: value })
                }
                required
              />
              <RatingInput
                label="Safety"
                value={formData.safety_rating}
                onChange={(value) =>
                  setFormData({ ...formData, safety_rating: value })
                }
                required
              />
              <RatingInput
                label="Comfort Level"
                value={formData.comfort_rating}
                onChange={(value) =>
                  setFormData({ ...formData, comfort_rating: value })
                }
                required
              />
              <RatingInput
                label="Accessibility"
                value={formData.accessibility_rating}
                onChange={(value) =>
                  setFormData({ ...formData, accessibility_rating: value })
                }
              />
              <RatingInput
                label="Service Quality"
                value={formData.service_rating}
                onChange={(value) =>
                  setFormData({ ...formData, service_rating: value })
                }
              />
              {/* Review Content */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  Your Review{" "}
                  <Text style={commonStyles.requiredAsterisk}>
                    {t("review.unknown")}
                  </Text>
                </Text>
                <TextInput
                  style={[commonStyles.input, commonStyles.textArea]}
                  placeholder={t(
                    "review.share_your_experience_at_this_location",
                  )}
                  value={formData.content}
                  onChangeText={(text) =>
                    setFormData({ ...formData, content: text })
                  }
                  multiline
                  numberOfLines={6}
                  textAlignVertical="top"
                  maxLength={1000}
                />
                <Text style={commonStyles.captionText}>
                  {formData.content.length}/1000
                </Text>
              </View>
              {/* Visit Details */}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_date")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowDatePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {visitDateTime.toLocaleDateString()}
                  </Text>
                  <Ionicons
                    name="calendar"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>
              {showDatePicker && (
                <DateTimePicker
                  value={visitDateTime}
                  mode="date"
                  display="default"
                  maximumDate={new Date()}
                  onChange={(event, selectedDate) => {
                    setShowDatePicker(Platform.OS === "ios");
                    if (selectedDate) {
                      const newDateTime = new Date(visitDateTime);
                      newDateTime.setHours(selectedDate.getHours());
                      newDateTime.setMinutes(selectedDate.getMinutes());

                      // Check if the combined date+time is in the future
                      const result = validateVisitDateTime(newDateTime);
                      if (!result.isValid) {
                        notify.error(result.errorMessage || "Invalid date");
                      }
                      setVisitDateTime(result.validatedDate);
                    }
                  }}
                />
              )}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_time")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowTimePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {visitDateTime.toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </Text>
                  <Ionicons
                    name="time"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>
              {showTimePicker && (
                <DateTimePicker
                  value={visitDateTime}
                  mode="time"
                  display="default"
                  onChange={(event, selectedTime) => {
                    setShowTimePicker(Platform.OS === "ios");
                    if (selectedTime) {
                      const newDateTime = new Date(visitDateTime);
                      newDateTime.setHours(selectedTime.getHours());
                      newDateTime.setMinutes(selectedTime.getMinutes());

                      // Check if the combined date+time is in the future
                      if (newDateTime > new Date()) {
                        notify.error(
                          t("review.visit_time_cannot_be_in_the_future"),
                        );
                        const now = new Date();
                        newDateTime.setHours(now.getHours());
                        newDateTime.setMinutes(now.getMinutes());
                      }

                      setVisitDateTime(newDateTime);
                    }
                  }}
                />
              )}
              <View style={commonStyles.formField}>
                <Text style={commonStyles.formLabel}>
                  {t("review.visit_type")}
                </Text>
                <TouchableOpacity
                  style={styles.dateButton}
                  onPress={() => setShowVisitTypePicker(true)}
                >
                  <Text style={styles.dateButtonText}>
                    {formData.visit_type.charAt(0).toUpperCase() +
                      formData.visit_type.slice(1)}
                  </Text>
                  <Ionicons
                    name="chevron-down"
                    size={20}
                    color={theme.colors.textSecondary}
                  />
                </TouchableOpacity>
              </View>
              {/* Visit Type Modal */}
              <Modal
                visible={showVisitTypePicker}
                transparent={true}
                animationType="slide"
              >
                <View style={commonStyles.modalOverlay}>
                  <TouchableOpacity
                    style={{ flex: 1 }}
                    activeOpacity={1}
                    onPress={() => setShowVisitTypePicker(false)}
                  />
                  <View style={commonStyles.modalContent}>
                    <View style={commonStyles.modalHeader}>
                      <Text style={commonStyles.modalTitle}>
                        Select Visit Type
                      </Text>
                      <TouchableOpacity
                        onPress={() => setShowVisitTypePicker(false)}
                      >
                        <Text style={commonStyles.modalDone}>
                          {t("review.done")}
                        </Text>
                      </TouchableOpacity>
                    </View>
                    <Picker
                      selectedValue={formData.visit_type}
                      onValueChange={(value) => {
                        setFormData({ ...formData, visit_type: value });
                      }}
                      style={{ height: 200 }}
                    >
                      <Picker.Item label="Solo" value="solo" />
                      <Picker.Item label="Couple" value="couple" />
                      <Picker.Item label="Family" value="family" />
                      <Picker.Item label="Group" value="group" />
                      <Picker.Item label="Business" value="business" />
                    </Picker>
                  </View>
                </View>
              </Modal>
              {/* Demographic Context Note */}
              <View style={styles.noteContainer}>
                <Ionicons
                  name="information-circle"
                  size={20}
                  color={theme.colors.textSecondary}
                />
                <Text style={styles.noteText}>
                  Your demographic profile will be attached to this review to
                  help others who share similar identities make informed
                  decisions.
                </Text>
              </View>
              {/* Submit Button */}
              <TouchableOpacity
                style={[
                  commonStyles.primaryButton,
                  loading && commonStyles.buttonDisabled,
                ]}
                onPress={handleSubmit}
                disabled={loading}
              >
                <Text style={commonStyles.primaryButtonText}>
                  {loading ? "Submitting..." : "Submit Review"}
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </TouchableWithoutFeedback>
      </ScrollView>
    </View>
  );
}

