              <Text style={styles.tapToUpgrade}>
                {t("premium.tap_to_upgrade")}
              </Text>
            </View>
          </TouchableOpacity>
        </View>
      );
    case "prompt":
    default:
      return (
        <TouchableOpacity
          style={styles.promptContainer}
          onPress={onUpgradePress || (() => router.push("/subscription"))}
