  onSelectOptimized: () => void;
  onStartNavigation?: () => void;
  isStartingNavigation?: boolean;
}

const RouteComparisonCard: React.FC<RouteComparisonCardProps> = ({
  comparison,
  onSelectOriginal,
  onSelectOptimized,
  onStartNavigation,
  isStartingNavigation = false,
}) => {
