        <Text style={styles.improvementText}>
          Safety improved by {improvement_summary.safety_improvement.toFixed(1)}{" "}
          points
        </Text>
      </View>

      {/* Route Comparison Cards */}
      <View style={styles.routesContainer}>
        {/* Original Route */}
        <TouchableOpacity
          style={[
            styles.routeCard,
