          <Text style={styles.startNavigationText}>
            {isStartingNavigation ? "Starting..." : "Start Navigation"}
          </Text>
          {!isStartingNavigation && (
            <Ionicons
              name="arrow-forward"
              size={20}
              color={theme.colors.background}
            />
          )}
        </TouchableOpacity>
      )}
    </View>
  );
};

