export default SearchBar;

import React from "react";
import { View, Text, StyleSheet } from "react-native";
import { Ionicons } from "@expo/vector-icons";
import { theme } from "@/styles/theme";
import { TimeSafetyData } from "@/store/locationsSlice";
import { commonStyles } from "@/styles/common";
import { useTranslation } from "react-i18next";

interface TimeSafetyChartProps {
  data: TimeSafetyData | null;
  loading: boolean;
}

const getTimePeriods = (t: (key: string) => string) =>
  [
    {
      key: "morning",
      label: t("map.morning"),
      icon: "sunny",
      hours: t("map.morning_hours"),
    },
    {
      key: "afternoon",
      label: t("map.afternoon"),
      icon: "partly-sunny",
      hours: t("map.afternoon_hours"),
    },
    {
      key: "evening",
      label: t("map.evening"),
      icon: "cloudy-night",
      hours: t("map.evening_hours"),
    },
    {
      key: "night",
      label: t("map.night"),
      icon: "moon",
      hours: t("map.night_hours"),
    },
  ] as const;

const getSafetyColor = (rating: number | null): string => {
  if (rating === null) return theme.colors.border;
  if (rating >= 4) return theme.colors.success;
  if (rating >= 3) return theme.colors.warning;
  return theme.colors.error;
};

const TimeSafetyChart: React.FC<TimeSafetyChartProps> = ({ data, loading }) => {
  const { t } = useTranslation();
  const TIME_PERIODS = getTimePeriods(t);

  if (loading) {
    return (
      <View style={styles.specContainer}>
        <Text style={commonStyles.loadingText}>
          {t("map.loading_time_data")}
        </Text>
      </View>
    );
  }

  if (!data || data.total_with_time === 0) {
    return (
      <View style={styles.specContainer}>
        <Text style={styles.emptyText}>
          {t("map.no_timebased_safety_data_yet")}
        </Text>
      </View>
    );
  }

  return (
    <View style={styles.specContainer}>
      <View style={styles.grid}>
        {TIME_PERIODS.map((period) => {
          const periodData = data[period.key];
          const hasData = periodData.review_count > 0;
          const safetyColor = getSafetyColor(periodData.avg_safety);

          return (
            <View key={period.key} style={styles.periodCard}>
              <View
                style={[
                  styles.iconContainer,
                  { backgroundColor: safetyColor + "20" },
                ]}
              >
                <Ionicons
                  name={period.icon as any}
                  size={24}
                  color={hasData ? safetyColor : theme.colors.textSecondary}
                />
              </View>
              <Text style={styles.periodLabel}>{period.label}</Text>
              <Text style={styles.periodHours}>{period.hours}</Text>
              {hasData ? (
                <>
                  <Text style={[styles.rating, { color: safetyColor }]}>
                    {periodData.avg_safety?.toFixed(1)}★
                  </Text>
                  <Text style={styles.reviewCount}>
                    {periodData.review_count} review
                    {periodData.review_count !== 1 ? "s" : ""}
                  </Text>
                </>
              ) : (
                <Text style={styles.noData}>{t("map.no_data")}</Text>
              )}
            </View>
          );
        })}
      </View>

      <Text style={styles.totalText}>
        Based on {data.total_with_time} review
        {data.total_with_time !== 1 ? "s" : ""} with time data
      </Text>
    </View>
  );
};

const styles = StyleSheet.create({
  specContainer: {
    backgroundColor: theme.colors.backgroundSecondary,
    borderRadius: 12,
    padding: 16,
    marginTop: 12,
  },
  title: {
    fontSize: 16,
    fontWeight: "700",
    color: theme.colors.text,
  },
  emptyText: {
    fontSize: 14,
    color: theme.colors.textSecondary,
    fontStyle: "italic",
  },
  grid: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 8,
  },
  periodCard: {
    flex: 1,
    minWidth: "45%",
    backgroundColor: theme.colors.background,
    borderRadius: 10,
    padding: 12,
    alignItems: "center",
  },
  iconContainer: {
    width: 44,
    height: 44,
    borderRadius: 22,
    alignItems: "center",
    justifyContent: "center",
    marginBottom: 8,
  },
  periodLabel: {
    fontSize: 14,
    fontWeight: "600",
    color: theme.colors.text,
  },
  periodHours: {
    fontSize: 11,
    color: theme.colors.textSecondary,
    marginBottom: 6,
  },
  rating: {
    fontSize: 18,
    fontWeight: "700",
  },
  reviewCount: {
    fontSize: 11,
    color: theme.colors.textSecondary,
  },
  noData: {
    fontSize: 12,
    color: theme.colors.textSecondary,
    fontStyle: "italic",
    marginTop: 4,
  },
  totalText: {
    fontSize: 11,
    color: theme.colors.textSecondary,
    textAlign: "center",
    marginTop: 12,
  },
});

export default TimeSafetyChart;

