import React, { useEffect } from "react";
import {
  View,
  Text,
  StyleSheet,
  Modal,
  TouchableOpacity,
  ScrollView,
  ActivityIndicator,
  Image,
} from "react-native";
import { SafeAreaView } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { theme } from "../styles/theme";
import { useAppDispatch, useAppSelector } from "../store/hooks";
import {
  fetchPublicUserProfile,
  fetchPublicUserReviews,
} from "../store/userSlice";
import { commonStyles } from "@/styles/common";
import { useTranslation } from "react-i18next";

interface UserProfileModalProps {
  visible: boolean;
  userId: string | null;
  onClose: () => void;
}

const UserProfileModal: React.FC<UserProfileModalProps> = ({
  visible,
  userId,
  onClose,
}) => {
  const { t } = useTranslation();
  const dispatch = useAppDispatch();
  const {
    publicProfile,
    publicProfileLoading,
    publicProfileError,
    publicReviews,
    publicReviewsLoading,
  } = useAppSelector((state) => state.user);

  useEffect(() => {
    if (visible && userId) {
      dispatch(fetchPublicUserProfile(userId));
      dispatch(fetchPublicUserReviews(userId));
    }
  }, [visible, userId, dispatch]);

  const renderDemographics = () => {
    if (!publicProfile || !publicProfile.show_demographics) return null;

    const demographics = [];

    if (
      publicProfile.race_ethnicity &&
      publicProfile.race_ethnicity.length > 0
    ) {
      demographics.push(publicProfile.race_ethnicity.join(", "));
    }
    if (publicProfile.gender) {
      demographics.push(publicProfile.gender);
    }
    if (publicProfile.lgbtq_status) {
      demographics.push("LGBTQ+");
    }
    if (
      publicProfile.disability_status &&
      publicProfile.disability_status.length > 0
    ) {
      demographics.push(
        "Disability: " + publicProfile.disability_status.join(", "),
      );
    }
    if (publicProfile.religion) {
      demographics.push(publicProfile.religion);
    }
    if (publicProfile.age_range) {
      demographics.push(publicProfile.age_range);
    }

    if (demographics.length === 0) return null;

    return (
      <View style={styles.section}>
        <Text style={commonStyles.sectionTitle}>
          {t("profile.demographics")}
        </Text>
        <View style={styles.demographicsContainer}>
          {demographics.map((demo, index) => (
            <View key={index} style={styles.demographicChip}>
              <Text style={styles.demographicText}>{demo}</Text>
            </View>
          ))}
        </View>
      </View>
    );
  };

  const renderReviews = () => {
    if (publicReviewsLoading) {
      return (
        <View style={commonStyles.centerContainer}>
          <ActivityIndicator size="small" color={theme.colors.primary} />
        </View>
      );
    }

    if (publicReviews.length === 0) {
      return (
        <Text style={styles.noReviewsText}>{t("profile.no_reviews_yet")}</Text>
      );
    }

    return publicReviews.map((review) => (
      <View key={review.id} style={styles.reviewItem}>
        <View style={styles.reviewHeader}>
          <Text style={styles.reviewLocationName} numberOfLines={1}>
            {review.location_name}
          </Text>
          <View style={styles.reviewRating}>
            <Ionicons name="star" size={16} color={theme.colors.mixedYellow} />
            <Text style={styles.reviewRatingText}>
              {review.overall_rating.toFixed(1)}
            </Text>
          </View>
        </View>
        <Text style={styles.reviewTitle} numberOfLines={1}>
          {review.title}
        </Text>
        <Text style={styles.reviewContent} numberOfLines={2}>
          {review.content}
        </Text>
        <Text style={styles.reviewDate}>
          {new Date(review.created_at).toLocaleDateString()}
        </Text>
      </View>
    ));
  };
  return (
    <Modal
      visible={visible}
      animationType="slide"
      transparent={true}
      onRequestClose={onClose}
    >
      <View style={commonStyles.modalOverlay}>
        <SafeAreaView style={commonStyles.modalContent}>
          {/* Header */}
          <View style={styles.specHeader}>
            <Text style={commonStyles.headerTitle}>
              {t("profile.user_profile")}
            </Text>
            <TouchableOpacity onPress={onClose}>
              <Ionicons name="close" size={24} color={theme.colors.text} />
            </TouchableOpacity>
          </View>

          {/* Content */}
          <ScrollView style={commonStyles.scrollView}>
            {publicProfileLoading ? (
              <View style={commonStyles.centerContainer}>
                <ActivityIndicator size="large" color={theme.colors.primary} />
                <Text style={commonStyles.loadingText}>
                  {t("profile.loading_profile")}
                </Text>
              </View>
            ) : publicProfileError ? (
              <View style={styles.errorContainer}>
                <Ionicons
                  name="alert-circle"
                  size={48}
                  color={theme.colors.error}
                />
                <Text style={commonStyles.textError}>{publicProfileError}</Text>
                <TouchableOpacity
                  style={commonStyles.primaryButton}
                  onPress={onClose}
                >
                  <Text style={commonStyles.primaryButtonText}>
                    {t("profile.close")}
                  </Text>
                </TouchableOpacity>
              </View>
            ) : publicProfile && !publicProfile.is_public ? (
              <View style={styles.privateContainer}>
                <Ionicons
                  name="lock-closed"
                  size={48}
                  color={theme.colors.textSecondary}
                />
                <Text style={styles.privateTitle}>
                  {t("profile.private_profile")}
                </Text>
                <Text style={styles.privateText}>
                  This user has set their profile to private.
                </Text>
              </View>
            ) : publicProfile ? (
              <>
                {/* Name Section */}
                {/* Name Section */}
                <View style={styles.nameSection}>
                  {publicProfile.avatar_url ? (
                    <Image
                      source={{ uri: publicProfile.avatar_url }}
                      style={styles.avatar}
                    />
                  ) : (
                    <View style={styles.avatarPlaceholder}>
                      <Ionicons
                        name="person"
                        size={40}
                        color={theme.colors.textSecondary}
                      />
                    </View>
                  )}
                  <Text style={styles.userName}>
                    {publicProfile.full_name || "TruGuide User"}
                  </Text>
                  <Text style={styles.memberSince}>
                    Member since{" "}
                    {new Date(publicProfile.created_at).toLocaleDateString()}
                  </Text>
                </View>

                {/* Stats Section */}
                <View style={styles.statsSection}>
                  <View style={styles.statItem}>
                    <Text style={styles.statNumber}>
                      {publicProfile.total_reviews}
                    </Text>
                    <Text style={styles.statLabel}>{t("profile.reviews")}</Text>
                  </View>
                </View>

                {/* Demographics Section */}
                {renderDemographics()}

                {/* Reviews section will be added in next step */}
                <View style={styles.section}>
                  <Text style={commonStyles.sectionTitle}>
                    {t("profile.recent_reviews")}
                  </Text>
                  {renderReviews()}
                </View>
              </>
            ) : null}
          </ScrollView>
        </SafeAreaView>
      </View>
    </Modal>
  );
};

